import java.io.File

private enum class RecordState { IDLE, RECORDING, UPLOADING }

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun RecordScreen(
    startRecordingImmediately: Boolean = false,
    onNavigateToSettings: () -> Unit,
) {
    val context = LocalContext.current
    val scope = rememberCoroutineScope()
    val snackbarHostState = remember { SnackbarHostState() }
    val settingsStore = remember { SettingsStore(context) }
    val apiClient = remember { ApiClient() }
    val graphQLClient = remember { GraphQLClient() }
    val recorder = remember { AudioRecorder(context) }

    val apiUrl by settingsStore.apiUrl.collectAsState(initial = "")
    val jwtToken by settingsStore.jwtToken.collectAsState(initial = "")

    var state by remember { mutableStateOf(RecordState.IDLE) }
    var elapsedSeconds by remember { mutableLongStateOf(0L) }
    var tagsInput by remember { mutableStateOf("") }
    var recordingFile by remember { mutableStateOf<File?>(null) }
    var hasPermission by remember {
        mutableStateOf(
            ContextCompat.checkSelfPermission(context, Manifest.permission.RECORD_AUDIO)
                == PackageManager.PERMISSION_GRANTED
        )
    }

    val permissionLauncher = rememberLauncherForActivityResult(
        ActivityResultContracts.RequestPermission()
    ) { granted -> hasPermission = granted }

    // Timer
    LaunchedEffect(state) {
        if (state == RecordState.RECORDING) {
            elapsedSeconds = 0L
            while (true) {
                delay(1000)
                elapsedSeconds++
            }
        }
    }

    // Auto-start for quick capture shortcut
    LaunchedEffect(startRecordingImmediately, hasPermission) {
        if (startRecordingImmediately && hasPermission && state == RecordState.IDLE) {
            recordingFile = recorder.start()
            state = RecordState.RECORDING
        }
    }

    fun startRecording() {
        if (!hasPermission) {
            permissionLauncher.launch(Manifest.permission.RECORD_AUDIO)
            return
        }
        if (apiUrl.isBlank() || jwtToken.isBlank()) {
            scope.launch { snackbarHostState.showSnackbar("Configure API URL and token in Settings") }
            return
        }
        recordingFile = recorder.start()
        state = RecordState.RECORDING
    }

    fun stopAndUpload() {
        val file = recorder.stop() ?: return
        state = RecordState.UPLOADING

        val tags = tagsInput.split(",")
            .map { it.trim() }
            .filter { it.isNotEmpty() }

        scope.launch {
            try {
                val uploadResponse = withContext(Dispatchers.IO) {
                    apiClient.uploadAudio(file, apiUrl, jwtToken)
                }
                withContext(Dispatchers.IO) {
                    graphQLClient.captureVoiceNote(uploadResponse.key, tags, apiUrl, jwtToken)
                }
                snackbarHostState.showSnackbar("Voice note captured!")
                tagsInput = ""
            } catch (e: Exception) {
                snackbarHostState.showSnackbar("Error: ${e.message}")
            } finally {
                file.delete()
                state = RecordState.IDLE
            }
        }
    }

    fun cancelRecording() {
        recorder.cancel()
        state = RecordState.IDLE
    }

    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text("Flotsam") },
                actions = {
                    IconButton(onClick = onNavigateToSettings) {
                        Icon(Icons.Default.Settings, contentDescription = "Settings")
                    }
                },
            )
        },
        snackbarHost = { SnackbarHost(snackbarHostState) },
    ) { padding ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(padding)
                .padding(24.dp),
            horizontalAlignment = Alignment.CenterHorizontally,
            verticalArrangement = Arrangement.Center,
        ) {
            when (state) {
                RecordState.IDLE -> {
                    if (!hasPermission) {
                        Text(
                            text = "Microphone permission is required to record voice notes.",
                            style = MaterialTheme.typography.bodyLarge,
                            textAlign = TextAlign.Center,
                            modifier = Modifier.padding(bottom = 24.dp),
                        )
                    }

                    if (apiUrl.isBlank() || jwtToken.isBlank()) {
                        Card(
                            colors = CardDefaults.cardColors(
                                containerColor = MaterialTheme.colorScheme.errorContainer,
                            ),
                            modifier = Modifier
                                .fillMaxWidth()
                                .padding(bottom = 24.dp),
                        ) {
                            Text(
                                text = "API URL and token not configured. Tap Settings to set up.",
                                modifier = Modifier.padding(16.dp),
                                color = MaterialTheme.colorScheme.onErrorContainer,
                            )
                        }
                    }

                    OutlinedTextField(
                        value = tagsInput,
